// Extract content from LLM response (handles both Ollama and z-ai format)
const response = items[0].json;
let content;

if (response.message && response.message.content) {
  // Ollama format: { message: { content: "..." } }
  content = response.message.content;
} else if (response.choices && response.choices[0] && response.choices[0].message) {
  // z-ai/OpenAI format: { choices: [{ message: { content: "..." } }] }
  content = response.choices[0].message.content;
} else if (response.response) {
  // Ollama generate format: { response: "..." }
  content = response.response;
} else {
  content = JSON.stringify(response);
}

// Clean content: remove markdown code blocks if present
content = content.replace(/```json\n/g, '').replace(/```\n/g, '').replace(/```/g, '').trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  // Try to extract JSON from text (fallback)
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      throw new Error('Failed to parse LLM response as JSON: ' + content.substring(0, 200));
    }
  } else {
    throw new Error('No JSON found in LLM response: ' + content.substring(0, 200));
  }
}

// Validate structure
if (!parsed.summaryDe || !parsed.items || !Array.isArray(parsed.items)) {
  throw new Error('Invalid LLM response structure: missing summaryDe or items array');
}

return [{ json: parsed }];

